## Reproduce the chart Elliot using the data from the names_year.csv file. If, after a couple of hours, you can get the chart close, but not exactly the same, that is okay. You will learn more to the degree you push yourself.

::: {#dc637dbd .cell execution_count=3}
``` {.python .cell-code}
elliot_data = (
    df.filter(pl.col("name").is_in(["Elliot", "Elliott"]))
    .group_by("year")
    .agg(pl.col("Total").sum().alias("count"))
    .sort("year")
    .with_columns(pl.lit("Elliot").alias("name"))
)

plot = (
    ggplot(elliot_data, aes(x="year", y="count", color="name"))
    + geom_line(size=1.2)
    + geom_vline(xintercept=1982, linetype="dashed", color="red")
    + geom_vline(xintercept=1985, linetype="dashed", color="red")
    + geom_vline(xintercept=2002, linetype="dashed", color="red")

    + geom_text(x=1981, y=2900, label="E.T. Released", hjust=1, size=9, color="black")
    + geom_text(x=1986, y=2900, label="Second Release", hjust=0, size=9, color="black")
    + geom_text(x=2003, y=2900, label="Third Release", hjust=0, size=9, color="black")

    + labs(
        title="Elliot...What?",
        x="year",
        y=""
    )
    + scale_y_continuous(
        limits=[0, 3000], 
        breaks=[0, 500, 1000, 1500, 2000, 2500, 3000],
        format='d' 
    )
    + scale_x_continuous(
        limits=[1950, 2025], 
        format='d'
    )
    + scale_color_manual(values=["#4E79A7"])

    + theme_grey() 
    + theme(
        plot_title=element_text(family="serif", face='bold', size=18),
        axis_title_x=element_text(family="serif", size=14),
        axis_text=element_text(family="serif", size=12),

        legend_title=element_text(family="serif"),
        legend_text=element_text(family="serif"),
        panel_grid_major=element_line(color="white"),
        panel_grid_minor=element_blank()
    )
    + ggsize(800, 500)
)

plot
```

